def _derive_mpd_from_segment(url: str, host: str) -> str:
    """If URL is a DASH segment/init (e.g. .../assets/<id>/video_1/seg-1.m4s), return .../assets/<id>/master.mpd."""
    try:
        from urllib.parse import urlparse
        if "tagmango" not in host and "tagmango" not in url:
            return ""
        parsed = urlparse(url)
        path = (parsed.path or "").strip("/")
        if "/assets/" not in path:
            return ""
        parts = path.split("/")
        if "assets" not in parts:
            return ""
        i = parts.index("assets")
        if i + 1 >= len(parts):
            return ""
        asset_id = parts[i + 1]
        if not asset_id or len(asset_id) < 4:
            return ""
        base = f"{parsed.scheme or 'https'}://{parsed.netloc or host}/assets/{asset_id}"
        return f"{base}/master.mpd"
    except Exception:
        return ""

