function normalizeTypeLabel(type, title = '') {
  const raw = String(type || '').toLowerCase();
  if (raw === 'serie' || raw === 'tv' || raw === 'series') return 'Serie';
  if (raw === 'film' || raw === 'movie') return 'Film';
  return title && title.match(/[SE]\d+/i) ? 'Serie' : 'Film';
}

